#include<bits/stdc++.h>
using namespace std;
const long long N=100010;
long long n,m,dfn[N],dfncnt,rnk[N],val[N],siz[N],son[N],top[N],fa[N],d[N];
vector<pair<long long,long long>> mp[N];
void dfs1(long long x,long long f=0)
{
    siz[x]=1;
    son[x]=-1;
    for(auto i:mp[x])
    {
        long long v=i.first,w=i.second;
        if(v!=f)
        {
            val[v]=w;
            fa[v]=x;
            d[v]=d[x]+1;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[son[x]]<siz[v])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            long long v=i.first;
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long sum;
        long long lson,rson,tag;
        node():tag(0){}
    }a[N*3];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    void pushdown(long long x)
    {
        long long l=a[x].l,r=a[x].r;
        long long mid=((l+r)>>1),ls=a[x].lson,rs=a[x].rson,tg=a[x].tag;
        a[ls].tag+=tg;
        a[rs].tag=(a[rs].tag+tg);
        a[ls].sum=(a[ls].sum+tg*(mid-l+1));
        a[rs].sum=(a[rs].sum+tg*(r-mid));
        a[x].tag=0;
    }
    long long build(long long l,long long r)
    {
        long long x=++cnt,mid=((l+r)>>1);
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=val[rnk[l]];
            return x;
        }
        a[x].lson=build(l,mid);
        a[x].rson=build(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long w)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].sum=(a[x].sum+(a[x].r-a[x].l+1)*w);
            a[x].tag+=w;
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,w);
        add(a[x].rson,l,r,w);
        pushup(x);
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
}t;
void addlian(long long x,long long y)
{
    long long tx=top[x],ty=top[y];
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            t.add(1,dfn[tx],dfn[x],1);
            x=fa[tx];
        }
        else
        {
            t.add(1,dfn[ty],dfn[y],1);
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.add(1,dfn[x]+1,dfn[y],1);
}
long long sumlian(long long x,long long y)
{
    long long tx=top[x],ty=top[y];
    long long ans=0;
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            ans+=t.getsum(1,dfn[tx],dfn[x]);
            x=fa[tx];
        }
        else
        {
            ans+=t.getsum(1,dfn[ty],dfn[y]);
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans+=t.getsum(1,dfn[x]+1,dfn[y]);
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(make_pair(v,0));
        mp[v].push_back(make_pair(u,0));
    }
    dfs1(1);
    dfs2(1,1);
    t.build(1,n);
    while(m--)
    {
        char op;
        long long x,y;
        cin>>op>>x>>y;
        if(op=='P')
        {
            addlian(x,y);
        }
        else
        {
            printf("%lld\n",sumlian(x,y));
        }
    }
    return 0;
}
